@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  padding: 0.75rem;
}

.toolbar {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 0.75rem;
  flex-wrap: wrap;
}

.search-wrap {
  position: relative;
  flex: 1;
  min-width: 200px;
}

.search-wrap i {
  position: absolute;
  left: 10px;
  top: 50%;
  transform: translateY(-50%);
  color: #888780;
  font-size: 14px;
}

.search-input {
  width: 100%;
  padding: 7px 10px 7px 32px;
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  outline: none;
  color: #05042E;
  background: #fff;
}

.search-input:focus {
  border-color: #469BC0;
}

.pills {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 0.75rem;
}

.pill {
  font-size: 11px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  cursor: pointer;
  border: 0.5px solid rgba(0, 0, 0, 0.12);
  background: #fff;
  color: #888780;
  white-space: nowrap;
}

.pill.active-all {
  background: #05042E;
  color: #fff;
  border-color: #05042E;
}

.pill.active-intake {
  background: #E6F1FB;
  color: #0C447C;
  border-color: #469BC0;
}

.pill.active-evaluation {
  background: #fee2e2;
  color: #991b1b;
  border-color: #fca5a5;
}

.pill.active-data {
  background: #ede9fe;
  color: #6d28d9;
  border-color: #c4b5fd;
}

.pill.active-compliance {
  background: #fef3c7;
  color: #92400e;
  border-color: #fcd34d;
}

.pill.active-sales {
  background: rgba(163, 232, 81, 0.15);
  color: #5a8a1a;
  border-color: rgba(163, 232, 81, 0.4);
}

.pill.active-end_of_life {
  background: #f1f5f9;
  color: #888780;
  border-color: #e2e8f0;
}

.cnt {
  font-size: 10px;
  font-weight: 700;
  margin-left: 4px;
  opacity: 0.7;
}

.stats {
  display: flex;
  gap: 8px;
  margin-bottom: 0.75rem;
}

.stat {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 8px;
  padding: 8px 14px;
  flex: 1;
}

.stat-label {
  font-size: 9px;
  font-weight: 600;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 2px;
}

.stat-value {
  font-size: 18px;
  font-weight: 700;
  color: #05042E;
}

.stat-value.blue {
  color: #469BC0;
}

.stat-value.green {
  color: #085041;
}

.stat-value.amber {
  color: #b45309;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.12);
  border-radius: 12px;
  overflow: hidden;
}

.card-header {
  background: #469BC0;
  padding: 0.6rem 1rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.card-title {
  font-size: 11px;
  font-weight: 700;
  color: #fff;
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

.record-count {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.8);
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  text-align: left;
  padding: 8px 10px;
  font-size: 10px;
  font-weight: 600;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.1);
  white-space: nowrap;
}

td {
  padding: 9px 10px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  font-size: 12px;
  color: #05042E;
  vertical-align: middle;
}

tr:last-child td {
  border-bottom: none;
}

tr:hover td {
  background: #f9f8f6;
}

.badge {
  font-size: 10px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 20px;
  display: inline-block;
  white-space: nowrap;
}

.b-intake {
  background: #E6F1FB;
  color: #0C447C;
  border: 1px solid #469BC0;
}

.b-evaluation {
  background: #fee2e2;
  color: #991b1b;
  border: 1px solid #fca5a5;
}

.b-data {
  background: #ede9fe;
  color: #6d28d9;
  border: 1px solid #c4b5fd;
}

.b-compliance {
  background: #fef3c7;
  color: #92400e;
  border: 1px solid #fcd34d;
}

.b-sales {
  background: rgba(163, 232, 81, 0.15);
  color: #5a8a1a;
  border: 1px solid rgba(163, 232, 81, 0.4);
}

.b-end-of-life {
  background: #f1f5f9;
  color: #888780;
  border: 1px solid #e2e8f0;
}

.b-default {
  background: #E0DFE1;
  color: #05042E;
}

.b-data-yes {
  background: #fee2e2;
  color: #991b1b;
}

.b-data-no {
  background: #E0DFE1;
  color: #05042E;
}

.b-erased {
  background: #A3E851;
  color: #05042E;
}

.grade {
  font-size: 11px;
  font-weight: 700;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.g-a {
  background: #A3E851;
  color: #05042E;
}

.g-b {
  background: #E6F1FB;
  color: #0C447C;
}

.g-c {
  background: #FAEEDA;
  color: #633806;
}

.g-f {
  background: #fee2e2;
  color: #991b1b;
}

.g-x {
  background: #E0DFE1;
  color: #05042E;
}

.asset-ref {
  font-family: monospace;
  font-size: 11px;
  color: #469BC0;
  background: #E6F1FB;
  padding: 2px 6px;
  border-radius: 4px;
}

.goto-btn {
  background: #05042E;
  border: none;
  border-radius: 50%;
  width: 26px;
  height: 26px;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: #A3E851;
}

.goto-btn:hover {
  background: #469BC0;
  color: #fff;
}

.empty {
  text-align: center;
  padding: 3rem;
  color: #888780;
  font-size: 12px;
}

.review-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #b45309;
  display: inline-block;
}

.pagination {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px;
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
  background: #f9f8f6;
}

.page-info {
  font-size: 11px;
  color: #888780;
}

.page-info strong {
  color: #05042E;
}

.page-btns {
  display: flex;
  align-items: center;
  gap: 6px;
}

.page-btn {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 4px 10px;
  font-size: 12px;
  font-family: "Figtree", sans-serif;
  font-weight: 600;
  cursor: pointer;
  color: #05042E;
}

.page-btn:hover {
  background: #469BC0;
  color: #fff;
  border-color: #469BC0;
}

.page-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.page-btn.active {
  background: #05042E;
  color: #A3E851;
  border-color: #05042E;
}

.page-size-select {
  font-size: 11px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 4px 6px;
  color: #05042E;
  outline: none;
}

