var allData = [];
var currentPage = 1;
var pageSize = 50;
var totalRecords = 0;
var activeStatus = 'All';
function statusBadgeClass(cat) {
  if (!cat) return 'b-default';
  var c = (cat || '').toLowerCase();
  if (c === 'intake') return 'b-intake';
  if (c === 'evaluation') return 'b-evaluation';
  if (c === 'data') return 'b-data';
  if (c === 'compliance') return 'b-compliance';
  if (c === 'sales') return 'b-sales';
  if (c === 'end_of_life') return 'b-end-of-life';
  return 'b-default';
}
function gradeClass(g) {
  if (!g) return 'g-x';
  var v = (g || '').toUpperCase();
  if (v === 'A') return 'g-a';
  if (v === 'B') return 'g-b';
  if (v === 'C') return 'g-c';
  if (v === 'F') return 'g-f';
  return 'g-x';
}
function buildPills() {
  var container = document.getElementById('statusPills');
  if (!container) return;
  var statuses = {};
  allData.forEach(function (r) {
    var s = r.status_name || 'Unknown';
    statuses[s] = (statuses[s] || 0) + 1;
  });
  var pillMap = {
    Received: 'active-received',
    Sold: 'active-sold',
    Repair: 'active-repair',
    Processing: 'active-processing'
  };
  var html = '<span class="pill ' + (activeStatus === 'All' ? 'active-all' : '') + '" onclick="window.setStatus(\'All\')">All <span class="cnt">' + totalRecords + '</span></span>';
  Object.keys(statuses).forEach(function (s) {
    var ac = pillMap[s] || 'active-received';
    html += '<span class="pill ' + (activeStatus === s ? ac : '') + '" onclick="window.setStatus(\'' + s + '\')">' + s + ' <span class="cnt">' + statuses[s] + '</span></span>';
  });
  container.innerHTML = html;
}
function buildStats() {
  var container = document.getElementById('statsRow');
  if (!container) return;
  var dataBearing = allData.filter(function (r) {
    return r.data_bearing;
  }).length;
  var erased = allData.filter(function (r) {
    return r.erasure_status === 'Erased';
  }).length;
  var needsReview = allData.filter(function (r) {
    return r.needs_review;
  }).length;
  container.innerHTML = '<div class="stat"><div class="stat-label">Total</div><div class="stat-value blue">' + totalRecords + '</div></div>' + '<div class="stat"><div class="stat-label">Data Bearing</div><div class="stat-value amber">' + dataBearing + '</div></div>' + '<div class="stat"><div class="stat-label">Erased</div><div class="stat-value green">' + erased + '</div></div>' + '<div class="stat"><div class="stat-label">Needs Review</div><div class="stat-value ' + (needsReview > 0 ? 'amber' : 'green') + '">' + needsReview + '</div></div>';
}
function buildPagination() {
  var totalPages = Math.ceil(totalRecords / pageSize);
  var pag = document.getElementById('pagination');
  var info = document.getElementById('pageInfo');
  var btns = document.getElementById('pageBtns');
  var count = document.getElementById('recordCount');
  if (!pag) return;
  var from = (currentPage - 1) * pageSize + 1;
  var to = Math.min(currentPage * pageSize, totalRecords);
  if (count) count.textContent = totalRecords + ' record' + (totalRecords !== 1 ? 's' : '');
  if (totalPages <= 1) {
    pag.style.display = 'none';
    return;
  }
  pag.style.display = 'flex';
  if (info) info.innerHTML = 'Showing <strong>' + from + '–' + to + '</strong> of <strong>' + totalRecords + '</strong>';
  var btnHtml = '<button class="page-btn" onclick="window.goToPage(' + (currentPage - 1) + ')" ' + (currentPage === 1 ? 'disabled' : '') + '>‹ Prev</button>';
  var startPage = Math.max(1, currentPage - 2);
  var endPage = Math.min(totalPages, startPage + 4);
  for (var i = startPage; i <= endPage; i++) {
    btnHtml += '<button class="page-btn' + (i === currentPage ? ' active' : '') + '" onclick="window.goToPage(' + i + ')">' + i + '</button>';
  }
  btnHtml += '<button class="page-btn" onclick="window.goToPage(' + (currentPage + 1) + ')" ' + (currentPage === totalPages ? 'disabled' : '') + '>Next ›</button>';
  if (btns) btns.innerHTML = btnHtml;
}
function renderTable(data) {
  var tbody = document.getElementById('tableBody');
  if (!tbody) return;
  if (!data.length) {
    tbody.innerHTML = '<tr><td colspan="10" class="empty">No assets found</td></tr>';
    return;
  }
  tbody.innerHTML = data.map(function (r) {
    var reviewDot = r.needs_review ? '<span class="review-dot" title="Needs review"></span>' : '';
    var ref = '<span class="asset-ref">' + (r.asset_ref || '—') + '</span>';
    var dataB = r.data_bearing ? '<span class="badge b-data-yes">Yes</span>' : '<span class="badge b-data-no">No</span>';
    var erasure = r.data_bearing && r.erasure_status === 'Erased' ? '<span class="badge b-erased" style="margin-left:4px">Erased</span>' : '';
    var grade = r.overall_grade ? '<span class="grade ' + gradeClass(r.overall_grade) + '">' + r.overall_grade.toUpperCase() + '</span>' : '<span style="color:#b0aeb8">—</span>';
    var status = '<span class="badge ' + statusBadgeClass(r.status_category) + '">' + (r.status_name || '—') + '</span>';
    return '<tr>' + '<td>' + reviewDot + '</td>' + '<td>' + ref + '</td>' + '<td>' + (r.item_type_name || '—') + '</td>' + '<td>' + (r.make_name || '—') + '</td>' + '<td>' + (r.model_name || '—') + '</td>' + '<td style="font-family:monospace;font-size:11px">' + (r.serial_number || '—') + '</td>' + '<td>' + dataB + erasure + '</td>' + '<td>' + grade + '</td>' + '<td>' + status + '</td>' + '<td><button class="goto-btn" onclick="window.goToAsset(' + r.asset_id + ')" title="View asset"><i class="ti ti-arrow-right" style="font-size:12px"></i></button></td>' + '</tr>';
  }).join('');
}
window.setStatus = function (s) {
  activeStatus = s;
  appsmith.updateModel({
    statusFilter: s === 'All' ? '' : s
  });
  appsmith.triggerEvent('onFilterStatus');
};
window.goToPage = function (p) {
  var totalPages = Math.ceil(totalRecords / pageSize);
  if (p < 1 || p > totalPages) return;
  currentPage = p;
  appsmith.updateModel({
    newPage: p
  });
  appsmith.triggerEvent('onPageChange');
};
window.changePageSize = function () {
  var sel = document.getElementById('pageSizeSelect');
  pageSize = parseInt(sel.value);
  appsmith.updateModel({
    newPageSize: pageSize,
    newPage: 1
  });
  appsmith.triggerEvent('onPageSizeChange');
};
window.goToAsset = function (id) {
  appsmith.updateModel({
    selectedAssetId: id
  });
  appsmith.triggerEvent('onGoToAsset');
};
function render(model) {
  allData = Array.isArray(model.assets) ? model.assets : [];
  totalRecords = model.total || allData.length;
  currentPage = model.page || 1;
  pageSize = model.pageSize || 50;
  buildPills();
  buildStats();
  buildPagination();
  renderTable(allData);
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

